Vẽ các đường thẳng\\
	$d_1\colon 2x+y=2$;\\
	$d_2\colon x-2y=1$;\\
	$d_3\colon y=2$;\\
	$d_4\colon x=3$.
	\begin{tikzpicture}[>=stealth,line width=0.7pt]
			\draw[color=white,fill=black!10] (-2,-2) rectangle (5,3);
			\path (-1/2,3) coordinate (A1);
