		($(A)!0.6!(C)$) coordinate (x')
		;
		\draw pic[draw=black, angle eccentricity=2.2, angle radius=0.3cm]{angle=C--I--D};
		\fill (x') node[shift={(0:0.3)}]{$\alpha$};
		\foreach \x/\g in {A/130,B/200,C/-90,D/0,H/-90,K/40}
