	$SC\parallel (P)$ khi đó $(P)\cap (SBC)=d_2$, với $d_2$ đi qua $N$ và $d_2\parallel SC$.\\
	Gọi $E=d_2\cap SB$.\\
	$AB\parallel (P)$ khi đó $(P)\cap (SAB)=d_3$, với $d_3$ đi qua $E$ và $d_3\parallel AB$.\\
	Gọi $F=d_3\cap SA$.\\
	Thiết diện của hình chóp $S.ABCD$ cắt bởi $(P)$ là tứ giác $AMEF$.

\immini{Xét $\left(SAC\right)$, gọi $\left\{H\right\}=AI\cap SO$.\\
	Xét $\triangle SOC$, ta có \begin{eqnarray*}
		&&\dfrac{SH}{HO}\cdot \dfrac{OA}{AC}\cdot \dfrac{CI}{IS}=1\\
		&\Leftrightarrow& \dfrac{SH}{HO}\cdot \dfrac{1}{2}\cdot 3=1\\
		&\Leftrightarrow& \dfrac{SH}{HO}=\dfrac{2}{3} \\
		&\Leftrightarrow& \dfrac{SH}{SO}=\dfrac{2}{5}.
	\end{eqnarray*}
	}
	{\begin{tikzpicture}[scale=1, font=\footnotesize, line join=round, line cap=round, >=stealth]

